def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 40 + np.log1p(cap) * 20
        fluctuation = 0.0
        decay_factor = np.exp(-usage * cap / 10)
        if usage > 5:
            base_priority += 8000 * usage ** 1.3
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 50 * np.sin(cap * 1.7)
            else:
                base_priority -= 50 * usage
            for i in range(1, 7):
                term = ((-1)**i) * np.cos(usage * np.pi * i * 0.9) * 25 / i
                fluctuation += term * decay_factor
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2 + 180 * (1 - delta ** 0.4)
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.5)) * 30 / j * decay_factor
            if int(cap * 4) % 5 == 1:
                base_priority += 60 * np.tan(cap / 20)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3) ** 2.2
            for k in range(1, 14):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 7 * k
                else:
                    fluctuation += (1 - val) * 22 / (k + 1)
                    if k == 11 and usage > 3.5:
                        fluctuation += 30
            if cap % 2.7 < 0.6:
                base_priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 22 / m
                    if m % 6 == 2:
                        fluctuation += 5 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 3)
                    if m == 15 and usage > 2.7:
                        fluctuation += 25
            if cap % 3.1 < 0.7:
                base_priority += 40 * np.cos(cap * 3.1)
        elif 1 < usage <= 2:
            base_priority += 950 * (usage - 1) ** 2.5
            for n in range(1, 21):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 28 / n
                    if n % 5 == 3:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 16 / (n + 2)
                    if n == 19 and usage > 1.8:
                        fluctuation += 20
            if cap % 2.2 < 0.4:
                base_priority += 33 * np.cos(cap * 2.5)
        elif 0.7 < usage <= 1:
            base_priority += 150 * (1 - usage) ** 2
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 16 / o
                if usage < 0.06 * o:
                    fluctuation -= 9 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.9:
                base_priority += np.log1p(cap * 25) * 38
            else:
                base_priority += (cap % 7) * 25
        else:
            base_priority += 320 * (1 - usage) ** 3
            for p in range(1, 20):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 15 / p
                if usage < 0.012 * p:
                    fluctuation -= 15 * p
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 35) * 50
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1400) % (s + 5) in {0,2}:
                    priority += s * 10
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 110
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 21 == 0:
            proximity += 18
        if int(cap * 1000) % 29 == 0:
            proximity -= 14
        if int(cap * 250) % 11 == 0:
            proximity += 17
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.025:
                proximity += 24 / w
            elif diff < 0.06:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 10):
                priority -= z * 15
        elif usage > 0.97:
            for aa in range(1, 9):
                priority += aa * 14
        if cap > 3.5:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2800) % 29 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 8):
                if (int(cap * 700) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
